mapper.select:
SELECT rq.id, rq.book_id, rq.reader_id, rq.request_date, rq.due_days, rq.status, rq.approve_date, rq.admin_id, rq.admin_remark, rq.reader_remark, rq.borrow_id, b.name AS book_name, r.name AS reader_name, au.username AS admin_name FROM borrow_request rq LEFT JOIN book b ON rq.book_id = b.id LEFT JOIN reader r ON rq.reader_id = r.id LEFT JOIN `user` au ON rq.admin_id = au.id
AND rq.status = #{status}
AND rq.reader_id = #{readerId}
ORDER BY rq.id DESC

mapper.update:
UPDATE borrow_request
SET status = #{status}, approve_date = #{approveDate}, admin_id = #{adminId},
    admin_remark = #{adminRemark}, borrow_id = #{borrowId}
WHERE id = #{id}
